    public static UBSVendorDimensionToSync find(
        VendAccount             _vendAccount ,
        boolean                 _forupdate        = false,
        ConcurrencyModel        _concurrencyModel = ConcurrencyModel::Auto)
    {
        UBSVendorDimensionToSync ubsVendorDimensionToSync;

        ubsVendorDimensionToSync.selectForUpdate(_forupdate);

        if (_forupdate  && _concurrencyModel != ConcurrencyModel::Auto)
        {
            ubsVendorDimensionToSync.concurrencyModel(_concurrencyModel);
        }

        if (_vendAccount != '')
        {
            select firstonly ubsVendorDimensionToSync
                where ubsVendorDimensionToSync.UBSAccountNum == _vendAccount;
        }

        return ubsVendorDimensionToSync;
    }
